import{_ as t,o as e,c as n,a2 as l}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 罪犯與海盜玩法：當個壞人也不錯","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/bandit-pirate.md","filePath":"bannerlord/bandit-pirate.md"}'),i={name:"bannerlord/bandit-pirate.md"};function s(r,a,d,o,h,p){return e(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="騎砍2-罪犯與海盜玩法-當個壞人也不錯" tabindex="-1">騎砍2 | 罪犯與海盜玩法：當個壞人也不錯 <a class="header-anchor" href="#騎砍2-罪犯與海盜玩法-當個壞人也不錯" aria-label="Permalink to &quot;騎砍2 | 罪犯與海盜玩法：當個壞人也不錯&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>正義太累？試試犯罪路線。掠奪村莊、走私貨物、襲擊商隊——壞事做盡，但賺錢超快。</p><hr><h2 id="一、犯罪玩法基礎" tabindex="-1">一、犯罪玩法基礎 <a class="header-anchor" href="#一、犯罪玩法基礎" aria-label="Permalink to &quot;一、犯罪玩法基礎&quot;">​</a></h2><h3 id="_1-1-幹壞事的代價" tabindex="-1">1.1 幹壞事的代價 <a class="header-anchor" href="#_1-1-幹壞事的代價" aria-label="Permalink to &quot;1.1 幹壞事的代價&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行為</th><th style="text-align:center;">賺多少</th><th>扣什麼</th></tr></thead><tbody><tr><td>掠奪村莊</td><td style="text-align:center;">2000-8000 金</td><td>聲譽 -、跟村莊/領主關係 -</td></tr><tr><td>攻擊商隊</td><td style="text-align:center;">2000-5000 金</td><td>跟該國開戰</td></tr><tr><td>偷竊貨物</td><td style="text-align:center;">500-2000 金</td><td>城市犯罪率 +</td></tr><tr><td>走私（Mod）</td><td style="text-align:center;">不定</td><td>被抓到扣關係</td></tr></tbody></table><h3 id="_1-2-聲譽的影響" tabindex="-1">1.2 聲譽的影響 <a class="header-anchor" href="#_1-2-聲譽的影響" aria-label="Permalink to &quot;1.2 聲譽的影響&quot;">​</a></h3><p>聲譽太低：</p><ul><li>領主不願意跟你打交道</li><li>城鎮可能拒絕你進入</li><li>但對犯罪玩法來說，這反而是一種身分標誌</li></ul><hr><h2 id="二、犯罪路線" tabindex="-1">二、犯罪路線 <a class="header-anchor" href="#二、犯罪路線" aria-label="Permalink to &quot;二、犯罪路線&quot;">​</a></h2><h3 id="_2-1-掠奪者" tabindex="-1">2.1 掠奪者 <a class="header-anchor" href="#_2-1-掠奪者" aria-label="Permalink to &quot;2.1 掠奪者&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>找沒有守軍保護的村莊 → 掠奪 →</span></span>
<span class="line"><span>賣戰利品 → 在被報復前換區域 →</span></span>
<span class="line"><span>重複</span></span></code></pre></div><ul><li>優點：收入高，來錢快</li><li>缺點：全村恨你，該國會派兵追殺你</li></ul><h3 id="_2-2-走私者" tabindex="-1">2.2 走私者 <a class="header-anchor" href="#_2-2-走私者" aria-label="Permalink to &quot;2.2 走私者&quot;">​</a></h3><p>需要對應 MOD（如 Fourberie）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在低價區買違禁品 → 運到高價區賣 →</span></span>
<span class="line"><span>賄賂守衛避免檢查 →</span></span>
<span class="line"><span>利潤比正常貿易高 2-3 倍</span></span></code></pre></div><h3 id="_2-3-海盜" tabindex="-1">2.3 海盜 <a class="header-anchor" href="#_2-3-海盜" aria-label="Permalink to &quot;2.3 海盜&quot;">​</a></h3><p>需要對應 MOD：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在沿海區域活動 → 攻擊海上商船 →</span></span>
<span class="line"><span>搶貨物 + 俘虜 → 賣掉 →</span></span>
<span class="line"><span>高風險高回報</span></span></code></pre></div><hr><h2 id="三、犯罪流生存技巧" tabindex="-1">三、犯罪流生存技巧 <a class="header-anchor" href="#三、犯罪流生存技巧" aria-label="Permalink to &quot;三、犯罪流生存技巧&quot;">​</a></h2><ol><li><strong>不要在同一個區域作案太久</strong>：掠奪完就換國</li><li><strong>保持高移速</strong>：全騎兵 + 少量貨物 = 跑得快</li><li><strong>賄賂守衛</strong>：犯罪率高的城鎮可以賄賂進入</li><li><strong>躲到偏遠地區</strong>：庫塞特東部、阿塞萊沙漠 = 沒人管</li></ol><hr><h2 id="四、犯罪流推薦-mod" tabindex="-1">四、犯罪流推薦 MOD <a class="header-anchor" href="#四、犯罪流推薦-mod" aria-label="Permalink to &quot;四、犯罪流推薦 MOD&quot;">​</a></h2><table tabindex="0"><thead><tr><th>MOD</th><th>功能</th></tr></thead><tbody><tr><td>Fourberie</td><td>完整犯罪系統（偷竊、暗殺、走私、賭博）</td></tr><tr><td>Bandit Militias</td><td>可以招募土匪當兵</td></tr></tbody></table><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./money-making.html">騎砍2 | 賺錢密技</a></li><li><a href="./cavalry-only.html">騎砍2 | 純騎兵流終極指南</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>`,36)])])}const u=t(i,[["render",s]]);export{b as __pageData,u as default};
